mapper.select:
SELECT o.out_id AS outId, o.out_time AS outTime, o.abnormal_status AS abnormalStatus, o.abnormal_note AS abnormalNote, i.food_name AS foodName, i.out_qty AS outQty, b.purchase_id AS purchaseId, b.check_id AS checkId FROM warehouse_out o LEFT JOIN warehouse_out_item i ON o.out_id = i.out_id LEFT JOIN warehouse_batch b ON i.batch_id = b.batch_id WHERE 1=1
AND o.abnormal_status = #{abnormalStatus}
AND o.out_time >= #{startTime}
AND o.out_time <= #{endTime}
ORDER BY o.out_time DESC
